/*! Minimal bootstrap-treeview-compatible adapter for TastyIgniter MediaManager folder dropdowns. */
(function($){'use strict';if(!$||$.fn.treeview)return;function parse(data){if(!data)return[];if(typeof data==='string'){try{return JSON.parse(data);}catch(e){return[];}}return data;}function render($el,nodes){var $ul=$('<ul class="list-group list-group-flush"></ul>');function add(list,parent){(list||[]).forEach(function(n){var $li=$('<li class="list-group-item"></li>').text(n.text||n.name||n.path||'').attr('data-nodeid',n.nodeId||'').data('node',n);$ul.append($li);if(n.nodes)add(n.nodes,n);});}add(nodes);$el.empty().append($ul);}$.fn.treeview=function(options){if(typeof options==='string')return this;return this.each(function(){var $el=$(this),nodes=parse(options&&options.data);render($el,nodes);$el.off('click.treeview').on('click.treeview','.list-group-item',function(e){$el.find('.list-group-item').removeClass('active');$(this).addClass('active');$el.trigger('nodeSelected',$(this).data('node')||{});});});};})(window.jQuery);
